sql:
SELECT name, job, salary
FROM crew_members
WHERE salary = (SELECT MAX(salary) FROM crew_members);

SELECT crew_members.name, departments.department_name
FROM crew_members
INNER JOIN departments ON crew_members.department_id = departments.department_id;

SELECT cm.name, cm.experience_years
FROM crew_members cm
WHERE cm.crew_id IN (
  SELECT crew_id
  FROM crew_assignments
  WHERE project_id IN (
    SELECT project_id
    FROM crew_assignments
    WHERE crew_id = (
      SELECT crew_id
      FROM crew_members
      WHERE experience_years = (
        SELECT MIN(experience_years) FROM crew_members
      )
    )
  )
) AND cm.experience_years < (
  SELECT MIN(experience_years) FROM crew_members
);

external_knowledge:
'current projects' refers to projects with a status of 'in production'.;
The total cost is computed as the sum of distinct salaries of the crew members in a department working on these current projects.;
Average years of experience is the mean of distinct experience years of those crew members.;
Departments are ranked by total salary cost and then by average experience years in descending order, with the highest salary cost and most experience leading the rankings.

